import {
  createBrowserRouter,
  redirect,
  RouterProvider,
} from "react-router-dom";

import Layout from "./components/Layout/Layout";
import ServerNav from "./components/ServerNav/ServerNav";
import Sidebar from "./components/Sidebar/Sidebar";
import Chat from "./pages/DM/Chat";
import Login from "./pages/Auth/Login";
import Register from "./pages/Auth/Register";
import { useEffect, useState } from "react";

function App() {
  const [isAuth, setIsAuth] = useState(false);
  const [token, setToken] = useState(null);
  const [isLoading, setIsLoading] = useState(true);

  console.log("PAGE RERENDER");
  useEffect(() => {
    const token = localStorage.getItem("token");
    const expiryDate = localStorage.getItem("expirationTime");

    if (!token) {
      return;
    }

    if (expiryDate) {
    }

    setToken(token);
    setIsAuth(true);
  }, []);

  console.log(token);
  console.log(isAuth);

  const router = createBrowserRouter([
    {
      path: "/register",
      element: <Register />,
    },
    {
      path: "/login",
      loader: () => {
        if (isAuth) return redirect("/");
        return null;
      },
      element: <Login />,
    },
    {
      path: "/",
      loader: () => {
        if (!isAuth) return redirect("/login");
        return null;
      },
      element: <Chat></Chat>,
    },
    {
      path: "/friends",
      loader: () => {
        if (!isAuth) return redirect("/login");
        return null;
      },
      element: <Chat></Chat>,
    },
  ]);

  return (
    <RouterProvider router={router}>
      <Layout
        nav={isAuth && <ServerNav token={token} />}
        sidebar={isAuth && <Sidebar token={token} />}
      ></Layout>
    </RouterProvider>
  );
}

export default App;
